import React, { Fragment, useState, useEffect } from "react";
import { getUserById } from "../../shop/dashboardUser/FetchApi";
import UserLayout from "../layout.js";
import axios from "axios";

const apiURL = process.env.REACT_APP_API_URL;
const BearerToken = () =>
  localStorage.getItem("jwt")
    ? JSON.parse(localStorage.getItem("jwt")).token
    : "";

const UserDocuments = () => {
  const [patientLicense, setPatientLicense] = useState(null);
  const [patientRegistrationCertificate, setPatientRegistrationCertificate] = useState(null);
  const [patientProofOfOwnership, setPatientProofOfOwnership] = useState(null);

  const [patientLicenseUploaded, setPatientLicenseUploaded] = useState(false);
  const [patientRegistrationCertificateUploaded, setPatientRegistrationCertificateUploaded] = useState(false);
  const [patientProofOfOwnershipUploaded, setPatientProofOfOwnershipUploaded] = useState(false);

  useEffect(() => {
    const fetchDocumentStatus = async () => {
      const loggedInUserId = localStorage.getItem("jwt")
        ? JSON.parse(localStorage.getItem("jwt")).user._id
        : "";
      if (loggedInUserId) {
        try {
          const response = await getUserById(loggedInUserId);
          if (response && response.User) {
            setPatientLicenseUploaded(response.User.patientLicenseUploaded);
            setPatientRegistrationCertificateUploaded(response.User.patientRegistrationCertificateUploaded);
            setPatientProofOfOwnershipUploaded(response.User.patientProofOfOwnershipUploaded);
          }
        } catch (error) {
          console.error("Error fetching document status:", error);
        }
      }
    };
    fetchDocumentStatus();
  }, []);

  const handleFileChange = (e, setter) => {
    setter(e.target.files[0]);
  };

    const handleUpload = async () => {
    const formData = new FormData();
    if (patientLicense) {
      formData.append("patientLicense", patientLicense);
    }
    if (patientRegistrationCertificate) {
      formData.append("patientRegistrationCertificate", patientRegistrationCertificate);
    }
    if (patientProofOfOwnership) {
      formData.append("patientProofOfOwnership", patientProofOfOwnership);
    }

    // Append logged-in user ID for authentication checks on server
    const loggedInUserId = localStorage.getItem("jwt")
      ? JSON.parse(localStorage.getItem("jwt")).user._id
      : "";
    formData.append("loggedInUserId", loggedInUserId);

    try {
      const response = await axios.post(`${apiURL}/api/user/upload-documents`, formData, {
        headers: {
          "Content-Type": "multipart/form-data",
          token: `Bearer ${BearerToken()}`,
        },
      });

      alert("Documents uploaded successfully!");
      if (response.data.urls.patientLicense) {
        setPatientLicenseUploaded(true);
      }
      if (response.data.urls.patientRegistrationCertificate) {
        setPatientRegistrationCertificateUploaded(true);
      }
      if (response.data.urls.patientProofOfOwnership) {
        setPatientProofOfOwnershipUploaded(true);
      }
    } catch (error) {

      alert("Error uploading documents. Please try again.");
    }
  };

  return (
    <UserLayout>
      <Fragment>
        <div className="flex flex-col w-full my-4 md:my-0 md:w-9/12 order-2 md:order-1">
          <div className="shadow-lg p-4 flex flex-col w-full mt-2">
            <h1 className="text-2xl font-semibold mb-4">Upload Patient Documents</h1>
            <div className="flex flex-col space-y-4">
              <div>
                <label htmlFor="patientLicense" className="block text-lg font-medium text-gray-700">
                  Patient License
                  {patientLicenseUploaded && <span className="ml-2 text-green-600 text-sm">(Uploaded)</span>}
                </label>
                <input
                  type="file"
                  id="patientLicense"
                  name="patientLicense"
                  onChange={(e) => handleFileChange(e, setPatientLicense)}
                  className="mt-1 block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100"
                />
              </div>
              <div>
                <label htmlFor="patientRegistrationCertificate" className="block text-lg font-medium text-gray-700">
                  Patient Registration Certificate
                  {patientRegistrationCertificateUploaded && <span className="ml-2 text-green-600 text-sm">(Uploaded)</span>}
                </label>
                <input
                  type="file"
                  id="patientRegistrationCertificate"
                  name="patientRegistrationCertificate"
                  onChange={(e) => handleFileChange(e, setPatientRegistrationCertificate)}
                  className="mt-1 block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100"
                />
              </div>
              <div>
                <label htmlFor="patientProofOfOwnership" className="block text-lg font-medium text-gray-700">
                  Patient Proof of Ownership
                  {patientProofOfOwnershipUploaded && <span className="ml-2 text-green-600 text-sm">(Uploaded)</span>}
                </label>
                <input
                  type="file"
                  id="patientProofOfOwnership"
                  name="patientProofOfOwnership"
                  onChange={(e) => handleFileChange(e, setPatientProofOfOwnership)}
                  className="mt-1 block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100"
                />
              </div>
              <button
                onClick={handleUpload}
                className="mt-4 px-4 py-2 bg-blue-600 text-white font-semibold rounded-md hover:bg-blue-700"
              >
                Upload Documents
              </button>
            </div>
          </div>
        </div>
      </Fragment>
    </UserLayout>
  );
};

export default UserDocuments;
